func handleChatMessage(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Invalid method", http.StatusMethodNotAllowed)
		return
	}

	username := r.Header.Get("X-Username")
	role := r.Header.Get("X-Role")

	if role == "" || username == "" {
		http.Error(w, "Missing user info in headers", http.StatusBadRequest)
		return
	}

	message, err := getChatMessageFromBody(r.Body)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	switch command := parseAdminCommand(message); command {
	case "/kick":
		if role == AdminRole || role == ModeratorRole {
			kickUser(username, message[6:])
			fmt.Fprintf(w, "User %s has been kicked", message[6:])
		} else {
			http.Error(w, "You don't have permission to kick users", http.StatusForbidden)
		}
	case "/ban":
		if role == AdminRole {
			banUser(username, message[5:])
			fmt.Fprintf(w, "User %s has been banned", message[5:])
		} else {
			http.Error(w, "You don't have permission to ban users", http.StatusForbidden)
		}
	case "/giveitems":
		if role == AdminRole || role == ModeratorRole {
			giveItems(username, message[10:])
			fmt.Fprintf(w, "Items given to user %s", message[10:])
		} else {
			http.Error(w, "You don't have permission to give items", http.StatusForbidden)
		}
	default:
		fmt.Fprintf(w, "Chat: %s", message)
	}
}

func getChatMessageFromBody(body io.ReadCloser) (string, error) {
	defer body.Close()
	buf := new(bytes.Buffer)
	if _, err := buf.ReadFrom(body); err != nil {
		return "", err
	}
	return buf.String(), nil
}

func parseAdminCommand(message string) string {
	command := strings.ToLower(strings.TrimSpace(message))
	if strings.HasPrefix(command, "/kick") || 
	   strings.HasPrefix(command, "/ban") || 
	   strings.HasPrefix(command, "/giveitems") {
		return command
	}
	return ""
}

